import { Box, HStack, Avatar, IconButton, Tooltip } from "@chakra-ui/react";
import { ArrowLeftIcon, ArrowRightIcon } from "@chakra-ui/icons";
import { useRef } from "react";

const artistas = [
    {
        nombre: 'Vandal Moon',
        img: 'https://f4.bcbits.com/img/0012748845_10.jpg'
    },
    {
        nombre: 'Avatar Metal',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'Ghost',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'Pale Waves',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'Chaos Chaos',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'The Chemical Brothers',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'iDKHOW',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'Franz Ferdinand',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'Daft Punk',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'Phantogram',
        img: 'data:image/jpeg;base64,'
    },
    {
        nombre: 'Bring Me The Horizon',
        img: 'data:image/jpeg;base64,'
    },
]

export default function Carrusel({ onSelectArtista, artistaSeleccionado }) {
  const scrollRef = useRef(null);

  const scroll = (direction) => {
    if (scrollRef.current) {
      const { scrollLeft, clientWidth } = scrollRef.current;
      const scrollAmount = direction === "left" ? -clientWidth / 2 : clientWidth / 2;
      scrollRef.current.scrollTo({
        left: scrollLeft + scrollAmount,
        behavior: "smooth",
      });
    }
  };

  return (
    <Box>
      <HStack
        ref={scrollRef}
        spacing={4}
        overflowX="scroll"
        px={4}
        py={4}
        pt={8}
        scrollBehavior="smooth"
        justify={artistas.length < 13 ? 'center' : undefined}
        css={{
          scrollbarWidth: "none",
          "&::-webkit-scrollbar": { display: "none" },
        }}
      >
        {artistas.map((a) => (
          <Tooltip 
            key={a.nombre}  
            label={a.nombre} 
            hasArrow  
            placement="top"  
            bg="gray.100" 
            color='gray.900'
            closeOnClick={false}
            openDelay={250}
          >
            <Avatar 
              key={a.nombre} 
              name={a.nombre} 
              src={a.img} 
              boxSize="100px" 
              onClick={() => onSelectArtista(a.nombre)}
              filter={artistaSeleccionado === '' || artistaSeleccionado === a.nombre ? 'grayscale(1%)' : 'blur(2px)'}
              sx={{
                cursor: "pointer",
                transition: "transform 0.25s ease",
                transform: artistaSeleccionado === a.nombre ? 'scale(1.3) translateY(-10px)': undefined,
                "&:hover": {
                  transform: "scale(1.3) translateY(-10px)",
                  filter: 'blur(0px)',
                },
              }}
            />
          </Tooltip>
        ))}
      </HStack>

      <Box align='center' display={artistas.length > 13 ? 'block' : 'none'}>
        {/* flecha izq */}
        <IconButton
          colorScheme='whiteAlpha'
          aria-label="left"
          icon={<ArrowLeftIcon color='white' />}
          onClick={() => scroll("left")}
          isRound={true}
          mr={8}
          _hover={{ transform: 'scale(1.3)' }}
        />

        {/* flecha der */}
        <IconButton
          colorScheme='whiteAlpha'
          aria-label="right"
          icon={<ArrowRightIcon color='white' />}
          onClick={() => scroll("right")}
          isRound={true}
          _hover={{ transform: 'scale(1.3)' }}
        />
      </Box>
    </Box>
  );
}
